const body = $input.item.json.body;
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;
const message = value?.messages?.[0];
const metadata = value?.metadata;

// Ignorar status updates (delivered, read)
if (!message) {
  return [{ json: { skip: true } }];
}

// Solo procesar mensajes de texto
if (message.type !== 'text') {
  return [{ json: { skip: true, reason: 'non_text' } }];
}

return [{
  json: {
    skip: false,
    phone: message.from,
    message: message.text?.body,
    businessPhoneId: metadata?.phone_number_id,
    displayPhoneNumber: metadata?.display_phone_number,
    messageId: message.id
  }
}];

// Construir historial de conversación para OpenAI
const messages = $input.all();
const professional = $('Get Professional Config').item.json;
const patient = $('Get Patient History').item?.json || {};
const incoming = $('Extract WhatsApp Data').item.json;

const businessName = professional.full_name || 'el despacho';
const businessConfig = professional.business_config || {};
const btConfig = professional.business_types?.config || {};

// Bugfix: Extract names/descriptions from custom fields object array
const customFields = btConfig.custom_fields || [];
const areas = customFields.map(f => f.description || f.name);
if (areas.length === 0) {
  areas.push('área del derecho', 'descripción del caso', 'modalidad');
}

const tono = businessConfig.ai_tone || 'profesional, empático y claro';
const modalities = businessConfig.modalities || ['Presencial', 'Videollamada', 'Llamada telefónica'];

const systemPrompt = `Eres el asistente virtual del despacho de abogados "${businessName}".\nTu objetivo es atender al cliente, entender su caso jurídico y agendar una consulta si aplica.\n\nTono: ${tono}\n\nINSTRUCCIONES:\n1. Saluda al cliente por su nombre si lo conoces.\n2. Pregunta de forma conversacional por: ${areas.join(', ')}.\n3. Modalidades disponibles para la consulta: ${modalities.join(', ')}.\n4. Cuando tengas nombre, fecha/hora preferida, área del derecho, descripción breve y modalidad → ejecuta la función Schedule_Legal_Consultation.\n5. Si el cliente hace preguntas de asesoría legal, responde orientativamente pero SIEMPRE agrega: "Esta información es orientativa. La evaluación definitiva de tu caso requiere una consulta formal con el abogado."\n6. NUNCA des opiniones jurídicas definitivas sobre casos específicos.\n7. Responde siempre en español.\n8. Sé conciso — máximo 3 oraciones por respuesta.`;

// Construir historial previo ordenado cronológicamente
const sortedMessages = [...messages]
  .filter(m => m.json && m.json.content)
  .sort((a, b) => new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime());

const historial = sortedMessages.map(m => ({
  role: m.json.sender === 'user' ? 'user' : 'assistant',
  content: m.json.content
}));

const openaiMessages = [
  { role: 'system', content: systemPrompt },
  ...historial,
  { role: 'user', content: incoming.message }
];

return [{
  json: {
    openaiMessages,
    professional,
    patient,
    incoming
  }
}];

