            "case_summary": { "type": "string", "description": "Descripción breve del caso en 1-2 oraciones" },
            "modality": { "type": "string", "description": "Modalidad: presencial, videollamada, telefono" }
          },
          "required": ["client_name", "date_time", "legal_area", "case_summary", "modality"]
        }
      }
    }
  ]
}

