const agentOutput = $('OpenAI Legal Agent').item.json;
const buildData = $('Build Legal Prompt').item.json;
const message = agentOutput.choices?.[0]?.message;
const toolCalls = message?.tool_calls;

if (toolCalls && toolCalls.length > 0) {
  try {
    const args = JSON.parse(toolCalls[0].function.arguments);
    // Bugfix: Calculate end_time (starts_at + 1 hour) for Google Calendar
    const startDate = new Date(args.date_time);
    const endDate = new Date(startDate.getTime() + 60 * 60 * 1000);
    const end_time = endDate.toISOString();

    return [{
      json: {
        has_function: true,
        client_name: args.client_name,
        date_time: args.date_time,
        end_time: end_time,
        legal_area: args.legal_area,
        case_summary: args.case_summary,
        modality: args.modality,
        custom_data: `Consulta jurídica - ${args.legal_area}: ${args.case_summary} (${args.modality})`,
        reply_text: message.content || `Perfecto ${args.client_name}, he agendado tu consulta jurídica. Te confirmo los detalles en breve.`,
        professional: buildData.professional,
        patient: buildData.patient,
        incoming: buildData.incoming
      }
    }];
  } catch (e) {
    return [{ json: { has_function: false, reply_text: message?.content || 'Hubo un problema. ¿Puedes repetir tu mensaje?', professional: buildData.professional, incoming: buildData.incoming } }];
  }
}

return [{
  json: {
    has_function: false,
    reply_text: message?.content || 'Hubo un problema. ¿Puedes repetir tu mensaje?',
    professional: buildData.professional,
    patient: buildData.patient,
    incoming: buildData.incoming
  }
}];

// Construir mensaje de confirmación personalizado
const args = $('Extract Arguments').item.json;
const date = new Date(args.date_time);
const fecha = date.toLocaleDateString('es-MX', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const hora = date.toLocaleTimeString('es-MX', { hour: '2-digit', minute: '2-digit' });

const modalityNormalized = (args.modality || '').toLowerCase().trim();
const modalidadTexto = {
  presencial: 'de forma presencial en el despacho',
  videollamada: 'por videollamada',
  telefono: 'por llamada telefónica',
  llamada: 'por llamada telefónica'
};

const confirmacion = `✅ *Consulta jurídica agendada*\n\n📋 *Área:* ${args.legal_area}\n📅 *Fecha:* ${fecha}\n⏰ *Hora:* ${hora}\n📍 *Modalidad:* ${modalidadTexto[modalityNormalized] || args.modality}\n\nEl abogado revisará tu caso y se pondrá en contacto contigo para confirmar. Si necesitas cancelar o reagendar, escríbenos con anticipación.\n\n_Esta información es orientativa. La evaluación definitiva de tu caso requiere la consulta formal con el abogado._`;

return [{ json: { confirmation_message: confirmacion, ...args } }];
